<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Bouncing Ball Physics Playground</title>
  <style>
    /* Dark Theme Styling */
    body {
      margin: 0;
      padding: 0;
      background-color: #121212;
      color: #e0e0e0;
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      overflow: hidden;
    }

    h1 {
      margin: 0 0 10px 0;
      font-size: 1.8rem;
      letter-spacing: 1px;
      color: #ffffff;
      text-shadow: 0 0 8px rgba(255, 255, 255, 0.2);
    }

    /* Canvas Container & Canvas */
    #canvas-container {
      position: relative;
      box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
      border-radius: 8px;
      overflow: hidden;
      border: 2px solid #333;
      background-color: #1a1a1a;
      margin-bottom: 20px;
    }

    #sim {
      display: block;
      background: radial-gradient(circle, #1e1e2f 0%, #0f0f15 100%);
      cursor: crosshair;
    }

    /* Controls */
    .controls {
      display: flex;
      gap: 15px;
      margin-bottom: 10px;
    }

    button {
      background-color: #2a2a3a;
      color: #ffffff;
      border: 1px solid #444;
      padding: 10px 20px;
      font-size: 1rem;
      font-weight: 600;
      border-radius: 6px;
      cursor: pointer;
      transition: all 0.2s ease;
      outline: none;
      user-select: none;
    }

    button:hover {
      background-color: #3a3a52;
      border-color: #555;
      transform: translateY(-1px);
    }

    button:active {
      transform: translateY(1px);
    }

    #drop {
      background-color: #2e7d32;
      border-color: #388e3c;
    }
    #drop:hover {
      background-color: #388e3c;
      border-color: #4caf50;
    }

    #play {
      background-color: #1565c0;
      border-color: #1976d2;
      min-width: 100px;
    }
    #play:hover {
      background-color: #1976d2;
      border-color: #2196f3;
    }

    #clear {
      background-color: #c62828;
      border-color: #d32f2f;
    }
    #clear:hover {
      background-color: #d32f2f;
      border-color: #f44336;
    }

    .instructions {
      font-size: 0.85rem;
      color: #888;
      margin-top: 5px;
      text-align: center;
    }
  </style>
</head>
<body>

  <h1>Physics Playground</h1>

  <div id="canvas-container">
    <canvas id="sim" width="600" height="500"></canvas>
  </div>

  <div class="controls">
    <button id="drop">Drop Ball</button>
    <button id="play">Pause</button>
    <button id="clear">Clear All</button>
  </div>

  <div class="instructions">
    Click inside the canvas to spawn balls with random colors and sizes!
  </div>

  <script>
    const canvas = document.getElementById('sim');
    const ctx = canvas.getContext('2d');

    // Simulation parameters
    const GRAVITY = 0.4;       // downward acceleration per step
    const RESTITUTION = 0.85;  // energy retention on bounce (0.85 = 15% loss)
    const DEFAULT_RADIUS = 16;

    // State
    let ballsList = [];
    let isPlaying = true;
    let animationFrameId = null;

    // Expose dimensions
    const w = canvas.width;
    const h = canvas.height;

    // Helper to generate a random vibrant color
    function getRandomColor() {
      const hues = [0, 30, 120, 200, 280, 330];
      const hue = hues[Math.floor(Math.random() * hues.length)] + Math.floor(Math.random() * 30 - 15);
      return `hsla(${hue}, 85%, 60%, 0.9)`;
    }

    // Draw a single ball with a nice gradient and shadow
    function drawBall(ball) {
      ctx.beginPath();
      const gradient = ctx.createRadialGradient(
        ball.x - ball.r * 0.3, ball.y - ball.r * 0.3, ball.r * 0.1,
        ball.x, ball.y, ball.r
      );
      gradient.addColorStop(0, '#ffffff');
      gradient.addColorStop(0.2, ball.color || '#ff5722');
      gradient.addColorStop(1, '#000000');

      ctx.fillStyle = gradient;
      ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);
      ctx.fill();
      ctx.closePath();
    }

    // Clear canvas and redraw everything
    function render() {
      ctx.clearRect(0, 0, w, h);
      for (let i = 0; i < ballsList.length; i++) {
        drawBall(ballsList[i]);
      }
    }

    // Physics step function
    function stepSimulation(dt = 1) {
      for (let i = 0; i < ballsList.length; i++) {
        const b = ballsList[i];

        // Apply gravity
        b.vy += GRAVITY * dt;

        // Update position
        b.x += b.vx * dt;
        b.y += b.vy * dt;

        // Bounce off Left / Right walls
        if (b.x - b.r < 0) {
          b.x = b.r;
          b.vx = -b.vx * RESTITUTION;
        } else if (b.x + b.r > w) {
          b.x = w - b.r;
          b.vx = -b.vx * RESTITUTION;
        }

        // Bounce off Top / Bottom walls
        if (b.y - b.r < 0) {
          b.y = b.r;
          b.vy = -b.vy * RESTITUTION;
        } else if (b.y + b.r > h) {
          b.y = h - b.r;
          b.vy = -b.vy * RESTITUTION;
        }
      }
      render();
    }

    // Main animation loop
    function loop() {
      if (isPlaying) {
        stepSimulation(1);
      }
      animationFrameId = requestAnimationFrame(loop);
    }

    // Programmatic API
    window.sim = {
      w: w,
      h: h,
      balls() {
        return ballsList;
      },
      addBall(x, y, vx = 0, vy = 0, r = DEFAULT_RADIUS) {
        const ball = {
          x: x,
          y: y,
          vx: vx,
          vy: vy,
          r: r,
          color: getRandomColor()
        };
        // Clamp initial position to keep ball inside canvas bounds
        if (ball.x - ball.r < 0) ball.x = ball.r;
        if (ball.x + ball.r > w) ball.x = w - ball.r;
        if (ball.y - ball.r < 0) ball.y = ball.r;
        if (ball.y + ball.r > h) ball.y = h - ball.r;

        ballsList.push(ball);
        render();
        return ball;
      },
      clear() {
        ballsList = [];
        render();
      },
      step(dt = 1) {
        stepSimulation(dt);
      }
    };

    // UI Event Listeners
    document.getElementById('drop').addEventListener('click', () => {
      const randomX = Math.random() * (w - 100) + 50;
      const randomY = 50;
      const randomVx = (Math.random() - 0.5) * 8;
      const randomVy = 0;
      const randomR = Math.floor(Math.random() * 15) + 12; // radius between 12 and 27
      window.sim.addBall(randomX, randomY, randomVx, randomVy, randomR);
    });

    const playBtn = document.getElementById('play');
    playBtn.addEventListener('click', () => {
      isPlaying = !isPlaying;
      playBtn.textContent = isPlaying ? 'Pause' : 'Play';
    });

    document.getElementById('clear').addEventListener('click', () => {
      window.sim.clear();
    });

    // Canvas click to spawn ball at cursor
    canvas.addEventListener('mousedown', (e) => {
      const rect = canvas.getBoundingClientRect();
      const clickX = e.clientX - rect.left;
      const clickY = e.clientY - rect.top;

      // Give it a slight random initial velocity
      const vx = (Math.random() - 0.5) * 10;
      const vy = (Math.random() - 0.5) * 10;
      const r = Math.floor(Math.random() * 15) + 12;

      window.sim.addBall(clickX, clickY, vx, vy, r);
    });

    // Initialize with a few starting balls
    window.sim.addBall(150, 150, 4, 2, 20);
    window.sim.addBall(300, 100, -3, 1, 25);
    window.sim.addBall(450, 200, 2, -4, 15);

    // Start loop
    loop();
  </script>
</body>
</html>
